const crypto = require('crypto');

function hashPassword(password) {
  return new Promise((resolve, reject) => {
    crypto.pbkdf2(password, 'salt', 100000, 64, 'sha512', (err, key) => {
      if (err) return reject(err);
      resolve(key.toString('hex'));
    });
  });
}